CREATE FUNCTION calculer_amende(nb_jours_retard INT)
RETURNS DECIMAL(10,2)
DETERMINISTIC
BEGIN
    DECLARE amende DECIMAL(10,2);
    IF nb_jours_retard <= 0 THEN
        SET amende = 0;
    ELSE
        SET amende = nb_jours_retard * 100;
        IF nb_jours_retard > 30 THEN
            SET amende = amende * 1.20;
        END IF;
    END IF;
    RETURN amende;
END;
```

