CREATE FUNCTION convertir_en_fcfa(prix_eur DECIMAL(10,2))
RETURNS INT
DETERMINISTIC
BEGIN
    DECLARE prix_xaf DECIMAL(15,2);
    SET prix_xaf = prix_eur * 655.957;
    RETURN CEILING(prix_xaf);
END;
